import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  // We'll fetch the top 5 markets by 24h volume from Polymarket and Kalshi
  // and then merge them to see the top 5 across both platforms.

  const polymarketId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const kalshiId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  const responses = await Promise.allSettled([
    callMcpSkill({
      toolId: polymarketId,
      toolName: "get_top_markets",
      args: { sortBy: "volume", limit: 10 }
    }),
    callMcpSkill({
      toolId: kalshiId,
      toolName: "discover_trending_markets",
      args: { sortBy: "volume_24h", limit: 10 }
    })
  ]);

  const polyData = responses[0].status === "fulfilled" ? responses[0].value.markets : [];
  const kalshiData = responses[1].status === "fulfilled" ? responses[1].value.trendingMarkets : [];

  const combined = [
    ...polyData.map(m => ({
      platform: "Polymarket",
      title: m.title,
      volume24h: m.volume24h,
      url: m.url,
      price: m.currentPrice ? (m.currentPrice * 100).toFixed(1) + "¢" : "N/A"
    })),
    ...kalshiData.map(m => ({
      platform: "Kalshi",
      title: m.title,
      volume24h: m.volume24h,
      url: m.url,
      price: m.yesPrice ? m.yesPrice + "¢" : "N/A"
    }))
  ];

  // Sort by 24h volume descending and take top 5
  const top5 = combined
    .filter(m => typeof m.volume24h === 'number')
    .sort((a, b) => b.volume24h - a.volume24h)
    .slice(0, 5);

  return {
    top_prediction_markets: top5,
    note: "Volume is based on the last 24 hours of trading activity."
  };
}

